CREATE TABLE caller_balances(phone_number VARCHAR PRIMARY KEY, total_seconds_used INTEGER DEFAULT(0), total_seconds_purchased INTEGER DEFAULT(0), last_call_at TIMESTAMP, created_at TIMESTAMP DEFAULT(CURRENT_TIMESTAMP));;
CREATE TABLE caller_insights(id VARCHAR PRIMARY KEY, phone_number VARCHAR, call_count INTEGER DEFAULT(1), first_seen TIMESTAMP, last_seen TIMESTAMP, avg_satisfaction DOUBLE, last_stage VARCHAR, topics_history VARCHAR, notes VARCHAR);;
CREATE TABLE caller_lookup(id VARCHAR PRIMARY KEY, phone_number VARCHAR, caller_name VARCHAR, career_stage VARCHAR, primary_challenge VARCHAR, specific_questions VARCHAR, industry_targets VARCHAR, submitted_at TIMESTAMP, created_at TIMESTAMP DEFAULT(CURRENT_TIMESTAMP), source_event_key VARCHAR, source_form_id VARCHAR, source_submission_id VARCHAR);;
CREATE TABLE caller_profiles(phone_number VARCHAR PRIMARY KEY, caller_name VARCHAR, email VARCHAR, linkedin_url VARCHAR, primary_challenge VARCHAR, specific_questions VARCHAR, intake_count INTEGER DEFAULT(0), resume_count INTEGER DEFAULT(0), last_form_id VARCHAR, last_submission_id VARCHAR, intake_last_submitted_at TIMESTAMP, last_resume_path VARCHAR, last_resume_processed_at TIMESTAMP, last_resume_stage VARCHAR, last_resume_bullet_quality VARCHAR, profile_summary VARCHAR, created_at TIMESTAMP DEFAULT(CURRENT_TIMESTAMP), updated_at TIMESTAMP DEFAULT(CURRENT_TIMESTAMP));;
CREATE TABLE caller_resumes(id VARCHAR PRIMARY KEY, phone_number VARCHAR, file_path VARCHAR, processed_data JSON, submitted_at TIMESTAMP DEFAULT(CURRENT_TIMESTAMP), processed_at TIMESTAMP);;
CREATE TABLE calls(id VARCHAR PRIMARY KEY, started_at TIMESTAMP, ended_at TIMESTAMP, duration_seconds INTEGER, topics_discussed VARCHAR, stage_assessed VARCHAR, escalation_requested BOOLEAN, raw_data JSON, phone_number VARCHAR);;
CREATE TABLE escalations(id VARCHAR PRIMARY KEY, call_id VARCHAR, "name" VARCHAR, contact VARCHAR, career_stage VARCHAR, reason VARCHAR, pain_points VARCHAR, created_at TIMESTAMP);;
CREATE TABLE feedback(id VARCHAR PRIMARY KEY, call_id VARCHAR, helpful BOOLEAN, rating INTEGER, feedback_text VARCHAR, would_recommend BOOLEAN, created_at TIMESTAMP, caller_name VARCHAR);;
CREATE TABLE intake_webhook_events(id VARCHAR PRIMARY KEY, event_key VARCHAR UNIQUE, form_id VARCHAR, submission_id VARCHAR, phone_number VARCHAR, caller_name VARCHAR, submitted_at TIMESTAMP, first_seen_at TIMESTAMP DEFAULT(CURRENT_TIMESTAMP), last_seen_at TIMESTAMP DEFAULT(CURRENT_TIMESTAMP), duplicate_count INTEGER DEFAULT(0));;
CREATE TABLE purchases(id VARCHAR PRIMARY KEY, phone_number VARCHAR, stripe_session_id VARCHAR, stripe_payment_intent VARCHAR, product_name VARCHAR, minutes_purchased INTEGER DEFAULT(0), amount_cents INTEGER DEFAULT(0), currency VARCHAR DEFAULT('usd'), status VARCHAR DEFAULT('unclaimed'), created_at TIMESTAMP DEFAULT(CURRENT_TIMESTAMP));;
CREATE UNIQUE INDEX idx_caller_lookup_source_event_key ON caller_lookup(source_event_key);;
CREATE UNIQUE INDEX idx_purchases_session ON purchases(stripe_session_id);;
